class Solution:
    def solve(self, nums: list[int], f: int) -> int:
        nums.sort()
        result = float('inf')
        left = 0
        right = 0
        current_sum = 0
        while right < len(nums):
            if current_sum + nums[right] <= f:
                current_sum += nums[right]
                right += 1
                if current_sum < result:
                    result = current_sum
            else:
                current_sum -= nums[left]
                left += 1
        return result

