#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int solve(vector<int>& nums, int f) {
        sort(nums.begin(), nums.end());
        int result = INT_MAX, left = 0, right = 0, current_sum = 0;
        while (right < nums.size()) {
            if (current_sum + nums[right] <= f) {
                current_sum += nums[right];
                right++;
                if (current_sum < result) {
                    result = current_sum;
                }
            } else {
                current_sum -= nums[left];
                left++;
            }
        }
        return result;
    }
};

int main() {
    int f;
    cin >> f;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    Solution s;
    cout << s.solve(nums, f);
    return 0;
}
